// Competitor GitHub release/commit feeds
return [
  { json: { competitor: 'ublock', kind: 'release', url: 'https://api.github.com/repos/gorhill/uBlock/releases?per_page=5' }},
  { json: { competitor: 'adblockplus', kind: 'release', url: 'https://api.github.com/repos/adblockplus/adblockpluschrome/releases?per_page=5' }},
  { json: { competitor: 'adguard', kind: 'release', url: 'https://api.github.com/repos/AdguardTeam/AdguardBrowserExtension/releases?per_page=5' }},
  { json: { competitor: 'ghostery', kind: 'release', url: 'https://api.github.com/repos/ghostery/ghostery-extension/releases?per_page=5' }},
  { json: { competitor: 'brave-shields', kind: 'release', url: 'https://api.github.com/repos/brave/brave-core/releases?per_page=3' }}
];

const items = $input.all();
const out = [];
for (const it of items) {
  const ctx = it.json;
  const releases = Array.isArray(ctx.data) ? ctx.data : (Array.isArray(ctx) ? ctx : []);
  // raw http output may be an array directly
  const arr = Array.isArray(ctx) ? ctx : releases;
  for (const r of arr) {
    if (!r || !r.html_url) continue;
    out.push({ json: {
      competitor: ctx.competitor || 'unknown',
      activity_type: 'release',
      url: r.html_url,
      title: r.tag_name + ' - ' + (r.name || ''),
      body: (r.body || '').slice(0, 4000),
      happened_at: r.published_at
    }});
  }
}
return out;

